{%? (#SOURCE:@ORDERBY='') {% order by DES asc %} {%  order by {%=#SOURCE:@ORDERBY %} asc %} %}')/ROWS/ROW

					for $r in sql('
        SELECT CYD02_DICTADOS.oi_dictado, CYD02_DICTADOS.d_dictado,
        CYD02_DICTADOS.f_inicio, CYD02_DICTADOS.f_fin    
				FROM CYD02_DICTADOS
				WHERE CYD02_DICTADOS.oi_estructura = {#SOURCE:@oi_estructura} 
				AND CYD02_DICTADOS.f_inicio < {DateTime(#source:@f_fin)}
				AND CYD02_DICTADOS.f_fin > {DateTime(#source:@f_inicio)}
				AND CYD02_DICTADOS.oi_dictado NOT IN (SELECT CYD02_ESTRUCT_DICT.oi_dictado FROM CYD02_ESTRUCT_DICT)
		')/ROWS/ROW
